mapper.select:
SELECT A.*, B.platform_name, C.company_name FROM tb_buyer_channel A LEFT JOIN tb_platform B ON A.platform_id = B.platform_id LEFT JOIN tb_company C ON A.company_id = C.company_id WHERE A.tenant_id = #{tenantId}
AND A.channel_name LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY A.channel_id DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}
